form:Form.form:Scripts:
		//Descarga un arhivo
function DOWNLOAD() {
	bajar(Ctrl("LIST").GetSelectAttrValue("file_name"));
}       

//Descarga un arhivo
function bajar(pFileName) {
	var np = GetProxy();
	var nSQL = np.SQLService();    
 	try {
		DownloadFile("INTERFACES\\"+pFileName, pFileName);
		return true;

 	} catch (e) {
		return false;
 	}
}         

//Descarga todos los archivos
function DOWNLOAD_ALL() {    
    download_files(Ctrl("LIST").RowsCount());
}    

//Descarga todos los archivos
function download_files(cantidad) {
  function download_next(i) {
    var FileName;

    if (i >= cantidad) {
      return;
    }   

    FileName = Ctrl('LIST').GetAttrValue(i,'file_name');
    if(!bajar(FileName)) return;

    setTimeout(function() {
      download_next(i + 1);
    }, 500);
  }
  download_next(0);
}          

function load() {
	CtrlEnabled("descargar",Ctrl('LIST').GetSelectRow() != null);
}        

